mapper.select:
SELECT a.atch_file_id , a.atch_file_group_id , a.file_seq , a.file_strg_path_dsctn , a.srvr_file_nm , a.file_nm , a.file_extn_nm , a.file_cn , a.file_sz , a.crt_dt , a.use_yn , a.reg_dt , TO_CHAR(a.reg_dt, 'YYYY-MM-DD HH24:MI:SS') , a.rgtr_id , TO_CHAR(a.mdfcn_dt, 'YYYY-MM-DD HH24:MI:SS') , a.mdfr_id FROM kids_own.tb_ca_e_file_trsm a WHERE 1=1
AND a.atch_file_group_id = #{atchFileGroupId}
ORDER BY a.atch_file_id DESC

SELECT a.atch_file_id , a.atch_file_group_id , a.file_seq , a.file_strg_path_dsctn , a.srvr_file_nm , a.file_nm , a.file_extn_nm , a.file_cn , a.file_sz , a.prvc_incl_yn , a.crt_dt , a.use_yn , a.reg_dt , TO_CHAR(a.reg_dt, 'YYYY-MM-DD HH24:MI:SS') , a.rgtr_id , TO_CHAR(a.mdfcn_dt, 'YYYY-MM-DD HH24:MI:SS') , a.mdfr_id FROM kids_own.tb_ca_e_file_trsm a WHERE 1=1
AND a.atch_file_id = #{atchFileId}
AND a.srvr_file_nm = #{srvrFileNm}

mapper.insert:
INSERT INTO kids_own.tb_ca_e_file_trsm (
                                  atch_file_id
                                , atch_file_group_id
                                , file_seq
                                , file_strg_path_dsctn
                                , srvr_file_nm
                                , prvc_incl_yn
                                , file_nm
                                , file_extn_nm
                                , file_cn
                                , file_sz
                                , crt_dt
                                , use_yn
                                , reg_dt
                                , rgtr_id
                                , mdfcn_dt
                                , mdfr_id
                        ) VALUES (
                                   #{atchFileId}
                                 , #{atchFileGroupId}
                                 , #{fileSeq}
                                 , #{fileStrgPathDsctn}
                                 , #{srvrFileNm}
                                 , #{prvcInclYyn}
                                 , #{fileNm}
                                 , #{fileExtnNm}
                                 , #{fileCn}
                                 , #{fileSz}
                                 , #{crtDt}
                                 , #{useYn}
                                 , NOW()
                                 , #{rgtrId}
                                 , NOW()
                                 , #{mdfrId}
                                 )

mapper.select:
SELECT * FROM ( SELECT atch_file_group_id , task_se_cd , task_se_trgt_id , use_yn , reg_dt , rgtr_id , mdfcn_dt , mdfr_id , ROW_NUMBER() OVER (ORDER BY atch_file_group_id DESC) as rn FROM kids_own.tb_ca_e_file_group_trsm WHERE task_se_cd = #{taskSeCd}
AND task_se_trgt_id = #{taskSeTrgtId}
AND atch_file_group_id = #{atchFileGroupId}
) sub WHERE rn = 1

mapper.insert:
INSERT INTO kids_own.tb_ca_e_file_group_trsm (
                                        atch_file_group_id
                                      , task_se_cd
                                      , task_se_trgt_id
                                      , use_yn
                                      , reg_dt
                                      , rgtr_id
                                      , mdfcn_dt
                                      , mdfr_id
                            ) VALUES (
                                       #{atchFileGroupId}
                                     , #{taskSeCd}
                                     , #{taskSeTrgtId}
                                     , #{useYn}
                                     , NOW()
                                     , #{rgtrId}
                                     , NOW()
                                     , #{mdfrId}
                                     )
ON CONFLICT (atch_file_group_id)
DO UPDATE SET
    use_yn = #{useYn} ,
    mdfcn_dt = NOW() ,
    mdfr_id = #{mdfrId}

INSERT INTO kids_own.tb_ca_l_cntn_info_log (
                                 cntn_log_sn
                               , acsr_id
                               , menu_sn
                               , qna
                               , url_addr
                               , prvc_incl_yn
                               , cntn_dt
                               , reg_dt
                               , rgtr_id
                        ) VALUES (
                                   #{cntnLogSn}
                                 , COALESCE(#{acsrId}, 'SYSTEM')
                                 , #{menuSn}
                                 , #{qna}
                                 , #{urlAddr}
                                 , #{prvcInclYn}
                                 , NOW()
                                 , NOW()
                                 , #{rgtrId}
                                 )
